import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';

interface OpeningAnimationProps {
  isOpening: boolean;
  result?: string | null;
}

const OpeningAnimation: React.FC<OpeningAnimationProps> = ({ isOpening, result }) => {
  return (
    <AnimatePresence>
      {isOpening ? (
        <motion.div
          key="opening"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="opening"
        >
          Открываем...
        </motion.div>
      ) : result ? (
        <motion.div
          key="result"
          initial={{ scale: 0.8 }}
          animate={{ scale: 1 }}
          className="result"
        >
          Ключ: {result}
        </motion.div>
      ) : null}
    </AnimatePresence>
  );
};

export default OpeningAnimation;
